ProductUnlockConfig = {}
ProductUnlockConfig.unlock = {}

function ProductUnlockConfig:init(config)
    self:initUnlockProduct(config)
end

function ProductUnlockConfig:initUnlockProduct(config)
    for i, v in pairs(config) do
        local item = {}
        item.Id = tonumber(v.Id)
        item.Icon = tostring(v.Icon)
        item.Name = tostring(v.Name)
        item.CoinId = tonumber(v.CoinId)
        item.CoinNum1 = tonumber(v.CoinNum1)
        item.UnlockDetail = tostring(v.UnlockDetail)
        item.ItemId = tonumber(v.ItemId)
        item.NotificationContent = tostring(v.NotificationContent)
        item.NotificationParams = tostring(v.NotificationParams)
        self.unlock[item.Id] = item
    end
    table.sort(self.unlock, function ( a, b )
        return a.id < b.id
    end)
end

function ProductUnlockConfig:getItemCfgById(id)
    local data = self.unlock[id]
    if data then
        return data
    end
end




return ProductUnlockConfig